import React from 'react';
import '../Styles/Global.css';

const AboutUs = () => {
  return (
    <section className="about-us-section">
      <div className="about-us-content">
        <h2>About NatureNest</h2>
        <p>
          At NatureNest, we believe plants are more than decor — they're living companions that enhance your space,
          improve air quality, and bring joy. Our team of plant lovers carefully curates the best plants for your home,
          whether you're a beginner or a green thumb.
        </p>
        <p>
          From indoor and outdoor varieties to medicinal and ornamental plants, we provide expert advice, quality products,
          and eco-friendly care tips — all in one green place.
        </p>
      </div>
    </section>
  );
};

export default AboutUs;
